"use client";

import { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import { fetchNewsSummary } from "@/lib/api";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import Link from "next/link";
import { ArrowLeft, Sparkles } from "lucide-react";

export default function NewsDetailPage() {
  const { id: rawId } = useParams<{ id: string }>();
  const id = decodeURIComponent(rawId);
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const load = () => {
    setLoading(true);
    setError("");
    fetchNewsSummary(id)
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [id]);

  return (
    <div className="space-y-6 max-w-2xl mx-auto">
      <Link href="/issues" className="inline-flex items-center text-gray-400 hover:text-white text-sm transition-colors">
        <ArrowLeft className="w-4 h-4 mr-1" /> 목록으로
      </Link>

      {loading && <LoadingSpinner text="쉬운 말로 정리하고 있어요..." />}
      {error && <ErrorMessage message={error} onRetry={load} />}

      {data && (
        <>
          <h1 className="text-2xl font-bold">{data.title}</h1>

          {/* AI 요약 */}
          <div className="bg-skyblue/10 border border-skyblue/30 rounded-xl p-5">
            <div className="flex items-center gap-2 mb-3">
              <Sparkles className="w-5 h-5 text-skyblue" />
              <h2 className="font-bold text-skyblue">쉽게 보는 요약</h2>
            </div>
            <p className="text-gray-200 leading-relaxed">{data.ai_summary}</p>
          </div>

          {/* 관련 종목 */}
          {data.related_stocks?.length > 0 && (
            <div>
              <h2 className="text-lg font-bold mb-3">관련 종목</h2>
              <div className="space-y-2">
                {data.related_stocks.map((s: any, i: number) => (
                  <Link
                    key={i}
                    href={`/stock/${s.stock_code}`}
                    className="block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors"
                  >
                    <div className="flex justify-between items-center">
                      <div>
                        <p className="font-medium">{s.stock_name}</p>
                        <p className="text-xs text-gray-400">{s.stock_code}</p>
                      </div>
                      <p className="text-sm text-gray-300">{s.reason}</p>
                    </div>
                  </Link>
                ))}
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}
